/**
 * Classification Result Types
 *
 * Canonical types for email classification results shared across all pipeline stages.
 * These types represent the final output of the classification pipeline and intermediate
 * stage results.
 */

/**
 * Represents a selected category label with confidence, score, and selection metadata.
 *
 * This is the canonical type for selected labels across all classification stages.
 * It encompasses label selection from multi-label selection, AI routing, and final decision stages.
 *
 * @property category - The category identifier (e.g., "PERSONAL", "WORK")
 * @property subtype - Optional subtype identifier (e.g., "WORK.MEETING", "PERSONAL.FAMILY")
 * @property confidence - Confidence score (0-100) indicating certainty of classification
 * @property score - Raw classification score used for ranking
 * @property isPrimary - Whether this is the primary (highest confidence) label
 * @property labelOrder - Order of label selection (1 = primary, 2+ = secondary labels)
 * @property selectionRationale - Human-readable explanation of why this label was selected
 */
export interface SelectedLabel {
  category: string;
  subtype?: string | null;
  confidence: number;
  score: number;
  isPrimary: boolean;
  labelOrder: number;
  selectionRationale: string;
}

/**
 * Represents a candidate category with scoring details before final selection.
 *
 * @property score - Final aggregated score for the category
 * @property confidence - Confidence level derived from the score
 * @property decision - Classification decision ('positive', 'candidate', 'rejected')
 * @property rationale - Explanation of the scoring and decision
 * @property selectedSubtypeId - ID of the selected subtype if applicable
 * @property hardAssertion - Whether this score came from a hard assertion (high confidence)
 * @property scoringComponents - Breakdown of score components for explainability
 */
export interface CandidateScore {
  score: number;
  confidence: number;
  decision: 'positive' | 'candidate' | 'rejected';
  rationale?: string;
  selectedSubtypeId?: string | null;
  hardAssertion?: boolean;
  scoringComponents?: Record<string, number | string | boolean>;
}

/**
 * Summary of the multi-label selection process.
 *
 * @property totalLabels - Number of labels selected
 * @property primaryCategory - The primary (highest confidence) category
 * @property confidenceRange - Min and max confidence scores [min, max]
 * @property selectionMethod - How labels were selected ('single_label', 'multi_label', 'none_selected')
 * @property needsAi - Whether AI classification is recommended
 * @property topCategories - Top ranked categories by score
 */
export interface SelectionSummary {
  totalLabels: number;
  primaryCategory: string | null;
  confidenceRange: [number, number];
  selectionMethod: 'single_label' | 'multi_label' | 'none_selected';
  needsAi: boolean;
  topCategories?: Array<{
    category: string;
    score: number;
  }>;
}

/**
 * Complete classification result with selected labels and metadata.
 *
 * @property selectedLabels - Array of selected category labels
 * @property candidateScores - Map of all candidate scores by category
 * @property selectionSummary - Summary of the selection process
 * @property needsAiClassification - Whether AI classification is required
 * @property processingDurationMs - Time taken for classification in milliseconds
 */
export interface ClassificationResult {
  selectedLabels: SelectedLabel[];
  candidateScores: Record<string, CandidateScore>;
  selectionSummary: SelectionSummary;
  needsAiClassification: boolean;
  processingDurationMs: number;
}

