    },
    topLevelCategories: {
      PERSONAL: {
        subtypes: {},
      },
    },
    attributes: {
      detectors: {},
      derived: {},
    },
    attributeRelevance: {},
    multiLabelPolicy: {
      maxLabels: 2,
      minSecondaryConfidence: 0.6,
      allowedCombinations: [],
    },
    settings: {
      disambiguation: {
        confidenceGapThreshold: 0.15,
      },
      archiveThreshold: {
        low_importance: 0.3,
        medium_importance: 0.5,
        high_importance: 0.8,
        defaultArchiveThreshold: 'medium_importance' as const,
      },
    },
  };

  describe('Constructor', () => {
    it('should initialize with valid configuration', () => {
      expect(() => new ClassificationPipeline(minimalConfig)).not.toThrow();
