/**
 * Classification Pipeline Orchestrator
 *
 * Orchestrates sequential execution of all 9 classification pipeline stages with proper
 * context management, error handling, and complete explainability trace generation.
 *
 * Pipeline Stages (Sequential Execution):
 * 1. Hard Assertions - Domain-based high-confidence categorization
 * 2. Strong Indicators - Weighted seed scoring with diminishing returns
 * 3. Rule-Based Scoring - Hierarchical pattern matching
 * 4. Attribute Detection - Cross-cutting signals detection
 * 5. Attribute Influence - Role-based bonuses
 * 6. Disambiguation - Pairwise conflict resolution
 * 7. Multi-label Selection - Confidence-based label assignment
 * 8. AI Routing - Selective AI classification for uncertain cases
 *    8a. AI Feature Extraction (if routed)
 *    8b. AI Classification (if routed)
 *    8c. Final Decision (always)
 * 9. Audit Trail Generation - Complete explainability traces
 *
 * Performance Target: < 10 seconds per email
 */

import { EmailMessage } from '../types/email-message';
import { ProcessingConfig } from '../types/category-configuration';
import { ClassificationResult, SelectedLabel, CandidateScore, SelectionSummary } from '../types/classification-result';
import { ClassificationContext } from '../stages/types';

// Import all stage execution functions
import { executeHardAssertions, HardAssertionStageConfig } from '../stages/hard-assertions';
import { executeStrongIndicators, StrongIndicatorStageConfig } from '../stages/strong-indicators';
import { executeRuleScoring, RuleScoringStageConfig } from '../stages/rule-scoring';
import { executeAttributeDetection, AttributeDetectionConfig } from '../stages/attribute-detection';
import { executeAttributeInfluence, AttributeInfluenceConfig } from '../stages/attribute-influence';
import { executeDisambiguation, DisambiguationConfig } from '../stages/disambiguation';
import { executeMultiLabelSelection, MultiLabelSelectionConfig } from '../stages/multi-label-selection';
import { executeAIRouting, AIRoutingConfig } from '../stages/ai-routing';
import { executeAIFeatureExtraction, AIFeatureExtractionConfig } from '../stages/ai-feature-extraction';
import { executeAIClassification, AIClassificationConfig } from '../stages/ai-classification';
import { executeFinalDecision, FinalDecisionConfig } from '../stages/final-decision';
import { executeAuditTrail, AuditTrailConfig } from '../stages/audit-trail';

// Validation utilities
import { validateEmailInput, validateConfigInput } from '../utils/validation';

/**
 * Error result for batch processing when individual email fails
 */
export interface ClassificationErrorResult {
  error: Error;
  emailId: string;
  processingDurationMs: number;
}

/**
 * Classification Pipeline orchestrator
 *
 * Manages sequential execution of all 9 classification stages with proper context
 * propagation, error handling, and performance tracking.
 */
export class ClassificationPipeline {
  private config: ProcessingConfig;

  /**
   * Initialize classification pipeline with validated configuration
   *
   * @param config - Complete processing configuration for all stages
   * @throws {Error} If configuration validation fails
   */
  constructor(config: ProcessingConfig) {
    // Validate configuration
    validateConfigInput(config, 'ProcessingConfig');

    // Validate confidence thresholds specifically
    const { confidenceThresholds } = config;
    if (
      !confidenceThresholds ||
      confidenceThresholds.highConfidence < 0 ||
      confidenceThresholds.mediumConfidence < 0 ||
      confidenceThresholds.lowConfidence < 0 ||
      confidenceThresholds.secondaryLabelMinGap < 0
    ) {
      throw new Error('Invalid confidence thresholds: all values must be non-negative');
    }

    this.config = config;
  }

  /**
   * Execute complete 9-stage classification pipeline on single email
   *
   * @param email - Email message to classify
   * @returns Complete classification result with selected labels and explainability traces
   * @throws {Error} If email validation fails or critical stage errors occur
   */
  async classify(email: EmailMessage): Promise<ClassificationResult> {
    const pipelineStartTime = Date.now();

    try {
      // Validate email input
      validateEmailInput(email, 'email');

      // Initialize classification context
      const context: ClassificationContext = {
        emailId: email.id,
        sessionId: `session-${email.id}-${Date.now()}`,
        categoryScores: {},
        hardAssertionsApplied: [],
        strongIndicatorSeeds: {},
        stageTimings: {},
        configurationRefs: {},
      };

      // Stage 1: Hard Assertions
      const hardAssertionsConfig: HardAssertionStageConfig = {
        confidenceThresholds: this.config.confidenceThresholds,
        categorySignals: this.config.categorySignals,
        domainLookup: this.config.domainLookup,
      };

      const hardAssertionsResult = executeHardAssertions(email, context, hardAssertionsConfig);

      // Update context with hard assertions results
      context.categoryScores = { ...context.categoryScores, ...hardAssertionsResult.updatedScores };
      context.hardAssertionsApplied = hardAssertionsResult.categoriesWithHardAssertions;
      context.stageTimings['hard-assertions'] = hardAssertionsResult.processingDurationMs;

      // Stage 2: Strong Indicators
      const strongIndicatorsConfig: StrongIndicatorStageConfig = {
        confidenceThresholds: this.config.confidenceThresholds,
        categorySignals: this.config.categorySignals,
        domainLookup: this.config.domainLookup,
      };

      const strongIndicatorsResult = executeStrongIndicators(email, context, strongIndicatorsConfig);

      // Update context with strong indicators results
      context.categoryScores = { ...context.categoryScores, ...strongIndicatorsResult.updatedScores };
      context.strongIndicatorSeeds = strongIndicatorsResult.seedScores;
      context.stageTimings['strong-indicators'] = strongIndicatorsResult.processingDurationMs;

      // Stage 3: Rule-Based Scoring
      const ruleScoringConfig: RuleScoringStageConfig = {
        topLevelCategories: this.config.topLevelCategories,
        confidenceThresholds: this.config.confidenceThresholds,
      };

      const ruleScoringResult = executeRuleScoring(email, context, ruleScoringConfig);

      // Update context with rule scoring results
      context.categoryScores = { ...context.categoryScores, ...ruleScoringResult.categoryScores };
      context.stageTimings['rule-scoring'] = ruleScoringResult.processingDurationMs;

      // Stage 4: Attribute Detection
      const attributeDetectionConfig: AttributeDetectionConfig = {
        attributes: this.config.attributes,
      };

      const attributeDetectionResult = executeAttributeDetection(email, context, attributeDetectionConfig);

      context.stageTimings['attribute-detection'] = attributeDetectionResult.processingDurationMs;

      // Stage 5: Attribute Influence
      const attributeInfluenceConfig: AttributeInfluenceConfig = {
        attributeRelevance: this.config.attributeRelevance,
        detectedAttributes: attributeDetectionResult.detectedAttributes,
      };

      const attributeInfluenceResult = executeAttributeInfluence(email, context, attributeInfluenceConfig);

      // Update context with attribute influence results
      context.categoryScores = { ...context.categoryScores, ...attributeInfluenceResult.updatedScores };
      context.stageTimings['attribute-influence'] = attributeInfluenceResult.processingDurationMs;

      // Stage 6: Disambiguation
      const disambiguationConfig: DisambiguationConfig = {
        confidenceGapThreshold: this.config.settings.disambiguation.confidenceGapThreshold,
        categoryScores: context.categoryScores,
      };

      const disambiguationResult = executeDisambiguation(email, context, disambiguationConfig);

      // Update context with disambiguation results
      context.categoryScores = { ...context.categoryScores, ...disambiguationResult.adjustedScores };
      context.stageTimings['disambiguation'] = disambiguationResult.processingDurationMs;

      // Stage 7: Multi-label Selection
      const multiLabelConfig: MultiLabelSelectionConfig = {
        multiLabelPolicy: this.config.multiLabelPolicy,
        confidenceThresholds: this.config.confidenceThresholds,
        candidateScores: context.categoryScores,
      };

      const multiLabelResult = executeMultiLabelSelection(email, context, multiLabelConfig);

      context.stageTimings['multi-label-selection'] = multiLabelResult.processingDurationMs;

      // Stage 8: AI Routing
      const aiRoutingConfig: AIRoutingConfig = {
        confidenceThresholds: this.config.confidenceThresholds,
        candidateScores: context.categoryScores,
        selectedLabels: multiLabelResult.selectedLabels,
      };

      const aiRoutingResult = executeAIRouting(email, context, aiRoutingConfig);

      context.stageTimings['ai-routing'] = aiRoutingResult.processingDurationMs;

      // Stage 8a/8b: AI Feature Extraction + Classification (if needed)
      let finalDecisionResult;

      if (aiRoutingResult.routedToAI) {
        // AI Feature Extraction
        const featureExtractionConfig: AIFeatureExtractionConfig = this.config.aiPrompts?.featureExtraction || {
          openai: {
            apiKey: process.env.OPENAI_API_KEY || '',
            model: 'gpt-4o-mini',
            temperature: 0.0,
            responseFormat: 'json_schema',
          },
          prompts: {
            systemPrompt: ['Extract key features from this email for classification.'],
            userPrompt: ['Email: {{email.subject}} {{email.bodyPlain}}'],
          },
          featureExtractionSchema: {
            name: 'feature_extraction',
            schema: {},
          },
          retryPolicy: {
            maxRetries: 3,
            backoffMs: 1000,
          },
        };

        const featureExtractionResult = await executeAIFeatureExtraction(
          email,
          { ...context, sessionId: context.sessionId, messageId: email.id },
          featureExtractionConfig
        );

        context.stageTimings['ai-feature-extraction'] = featureExtractionResult.processingDurationMs;

        // AI Classification
        const aiClassificationConfig: AIClassificationConfig = this.config.aiPrompts?.finalClassification || {
          openai: {
            apiKey: process.env.OPENAI_API_KEY || '',
            model: 'gpt-4o-mini',
            temperature: 0.0,
            responseFormat: 'json_schema',
          },
          prompts: {
            systemPrompt: ['Classify this email into categories.'],
            userPrompt: ['Email: {{email.subject}} {{email.bodyPlain}}'],
          },
          classificationSchema: {
            name: 'final_classification',
            schema: {},
          },
          skipConditions: {
            highConfidenceThreshold: 0.8,
            skipReasons: [],
          },
          retryPolicy: {
            maxRetries: 3,
            backoffMs: 1000,
          },
        };

        const aiClassificationResult = await executeAIClassification(
          email,
          { ...context, sessionId: context.sessionId, messageId: email.id, extractedFeatures: featureExtractionResult.extractedFeatures },
          aiClassificationConfig
        );

        context.stageTimings['ai-classification'] = aiClassificationResult.processingDurationMs;

        // Stage 8c: Final Decision
        const finalDecisionConfig: FinalDecisionConfig = {
          archiveThresholds: this.config.settings.archiveThreshold,
          defaultArchiveThreshold: this.config.settings.archiveThreshold.defaultArchiveThreshold,
          labelAssignmentRules: this.config.multiLabelPolicy,
        };

        finalDecisionResult = executeFinalDecision(
          email,
          { ...context, sessionId: context.sessionId, messageId: email.id, aiClassification: aiClassificationResult.classification },
          finalDecisionConfig
        );

        context.stageTimings['final-decision'] = finalDecisionResult.processingDurationMs;
      } else {
        // Skip AI, go directly to final decision
        const finalDecisionConfig: FinalDecisionConfig = {
          archiveThresholds: this.config.settings.archiveThreshold,
          defaultArchiveThreshold: this.config.settings.archiveThreshold.defaultArchiveThreshold,
          labelAssignmentRules: this.config.multiLabelPolicy,
        };

        // Use multi-label selection results as input
        finalDecisionResult = executeFinalDecision(
          email,
          { ...context, sessionId: context.sessionId, messageId: email.id, selectedLabels: multiLabelResult.selectedLabels },
          finalDecisionConfig
        );

        context.stageTimings['final-decision'] = finalDecisionResult.processingDurationMs;
      }

      // Stage 9: Audit Trail Generation (optional, for database persistence)
      // This stage is not part of the core classification result, but can be used
      // to generate explainability traces for database storage

      // Aggregate final results
      const pipelineEndTime = Date.now();
      const totalDuration = pipelineEndTime - pipelineStartTime;

      // Build candidate scores map
      const candidateScores: Record<string, CandidateScore> = {};
      Object.keys(context.categoryScores).forEach((category) => {
        const score = context.categoryScores[category];
        candidateScores[category] = {
          score,
          confidence: this.calculateConfidence(score),
          decision: this.determineDecision(score),
          rationale: `Score: ${score.toFixed(2)}`,
          hardAssertion: context.hardAssertionsApplied.includes(category),
        };
      });

      // Convert final decision labels to SelectedLabel format
      const selectedLabels: SelectedLabel[] = [];
      if (finalDecisionResult.assignedLabels.primary) {
        selectedLabels.push({
          category: finalDecisionResult.assignedLabels.primary,
          confidence: candidateScores[finalDecisionResult.assignedLabels.primary]?.confidence || 0,
          score: candidateScores[finalDecisionResult.assignedLabels.primary]?.score || 0,
          isPrimary: true,
          labelOrder: 1,
          selectionRationale: 'Primary label assigned by final decision stage',
        });
      }

      finalDecisionResult.assignedLabels.secondary.forEach((category, index) => {
        selectedLabels.push({
          category,
          confidence: candidateScores[category]?.confidence || 0,
          score: candidateScores[category]?.score || 0,
          isPrimary: false,
          labelOrder: index + 2,
          selectionRationale: 'Secondary label assigned by final decision stage',
        });
      });

      // Build selection summary
      const selectionSummary: SelectionSummary = {
        totalLabels: selectedLabels.length,
        primaryCategory: selectedLabels.find((l) => l.isPrimary)?.category || null,
        confidenceRange: this.calculateConfidenceRange(selectedLabels),
        selectionMethod: selectedLabels.length === 0 ? 'none_selected' : selectedLabels.length === 1 ? 'single_label' : 'multi_label',
        needsAi: aiRoutingResult.routedToAI,
        topCategories: Object.entries(context.categoryScores)
          .sort(([, a], [, b]) => b - a)
          .slice(0, 3)
          .map(([category, score]) => ({ category, score })),
      };

      // Return complete classification result
      return {
        selectedLabels,
        candidateScores,
        selectionSummary,
        needsAiClassification: aiRoutingResult.routedToAI,
        processingDurationMs: totalDuration,
      };
    } catch (error) {
      // Capture error with processing time
      const pipelineEndTime = Date.now();
      throw new Error(
        `Classification pipeline failed for email ${email.id} after ${pipelineEndTime - pipelineStartTime}ms: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Process multiple emails sequentially
   *
   * @param emails - Array of email messages to classify
   * @returns Array of classification results or error results
   */
  async classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>> {
    const results: Array<ClassificationResult | ClassificationErrorResult> = [];

    for (const email of emails) {
      const startTime = Date.now();
      try {
        const result = await this.classify(email);
        results.push(result);
      } catch (error) {
        // Continue processing batch on individual email error
        results.push({
          error: error instanceof Error ? error : new Error(String(error)),
          emailId: email.id,
          processingDurationMs: Date.now() - startTime,
        });
      }
    }

    return results;
  }

  /**
   * Calculate confidence score from raw score
   */
  private calculateConfidence(score: number): number {
    // Map score to 0-100 confidence range
    // Simple linear mapping (can be enhanced with sigmoid or other curves)
    return Math.min(100, Math.max(0, score * 10));
  }

  /**
   * Determine decision category based on score
   */
  private determineDecision(score: number): 'positive' | 'candidate' | 'rejected' {
    const { highConfidence, mediumConfidence } = this.config.confidenceThresholds;

    if (score >= highConfidence) {
      return 'positive';
    } else if (score >= mediumConfidence) {
      return 'candidate';
    } else {
      return 'rejected';
    }
  }

  /**
   * Calculate confidence range from selected labels
   */
  private calculateConfidenceRange(labels: SelectedLabel[]): [number, number] {
    if (labels.length === 0) {
      return [0, 0];
    }

    const confidences = labels.map((l) => l.confidence);
    return [Math.min(...confidences), Math.max(...confidences)];
  }
}

