/**
 * Execute complete 9-stage classification pipeline on single email
 *
 * MINIMAL MVP Implementation for Phase 3.5.2:
 * - Executes stages 1-7 (hard assertions through multi-label selection)
 * - Skips AI stages (8-9) which will be integrated in Phase 3.6
 * - Returns classification result based on rule-based pipeline only
 *
 * @param email - Email message to classify
 * @returns Complete classification result with selected labels and explainability traces
 * @throws {Error} If email validation fails or critical stage errors occur
 */
async classify(email: EmailMessage): Promise<ClassificationResult> {
  const pipelineStartTime = Date.now();

  try {
    // Validate email input
    validateEmailInput(email, 'email');

    // Initialize classification context
    const context: ClassificationContext = {
      emailId: email.id,
      sessionId: `session-${email.id}-${Date.now()}`,
      categoryScores: {},
      hardAssertionsApplied: [],
      strongIndicatorSeeds: {},
      stageTimings: {},
      configurationRefs: {},
    };

    // Stage 1: Hard Assertions
    const hardAssertionsConfig: HardAssertionStageConfig = {
      confidenceThresholds: this.config.confidenceThresholds,
      categorySignals: this.config.categorySignals,
      domainLookup: this.config.domainLookup,
    };

    const hardAssertionsResult = executeHardAssertions(email, context, hardAssertionsConfig);

    // Update context with hard assertions results
    context.categoryScores = { ...context.categoryScores, ...hardAssertionsResult.updatedScores };
    context.hardAssertionsApplied = hardAssertionsResult.categoriesWithHardAssertions;
    context.stageTimings['hard-assertions'] = hardAssertionsResult.processingDurationMs;

    // Stage 2: Strong Indicators
    const strongIndicatorsConfig: StrongIndicatorStageConfig = {
      confidenceThresholds: this.config.confidenceThresholds,
      categorySignals: this.config.categorySignals,
      domainLookup: this.config.domainLookup,
    };

    const strongIndicatorsResult = executeStrongIndicators(email, context, strongIndicatorsConfig);

    // Update context with strong indicators results
    context.categoryScores = { ...context.categoryScores, ...strongIndicatorsResult.updatedScores };
    context.strongIndicatorSeeds = strongIndicatorsResult.seedScores;
    context.stageTimings['strong-indicators'] = strongIndicatorsResult.processingDurationMs;

    // Stage 3: Rule-Based Scoring
    const ruleScoringConfig: RuleScoringStageConfig = {
      topLevelCategories: this.config.topLevelCategories,
      confidenceThresholds: this.config.confidenceThresholds,
    };

    const ruleScoringResult = executeRuleScoring(email, context, ruleScoringConfig);

    // Update context with rule scoring results
    context.categoryScores = { ...context.categoryScores, ...ruleScoringResult.categoryScores };
    context.stageTimings['rule-scoring'] = ruleScoringResult.processingDurationMs;

    // Stage 4: Attribute Detection
    const attributeDetectionConfig: AttributeDetectionConfig = {
      attributes: this.config.attributes,
    };

    const attributeDetectionResult = executeAttributeDetection(email, context, attributeDetectionConfig);

    context.stageTimings['attribute-detection'] = attributeDetectionResult.processingDurationMs;

    // Stage 5: Attribute Influence
    const attributeInfluenceConfig: AttributeInfluenceConfig = {
      attributeRelevance: this.config.attributeRelevance,
      detectedAttributes: attributeDetectionResult.detectedAttributes,
    };

    const attributeInfluenceResult = await executeAttributeInfluence(email, context, attributeInfluenceConfig);

    // Update context with attribute influence results
    context.categoryScores = { ...context.categoryScores, ...attributeInfluenceResult.updatedScores };
    context.stageTimings['attribute-influence'] = attributeInfluenceResult.processingDurationMs;

    // Stage 6: Disambiguation
    const disambiguationConfig: DisambiguationConfig = {
      confidenceGapThreshold: this.config.settings.disambiguation.confidenceGapThreshold,
      categoryScores: context.categoryScores,
    };

    const disambiguationResult = await executeDisambiguation(email, context, disambiguationConfig);

    // Update context with disambiguation results
    context.categoryScores = { ...context.categoryScores, ...disambiguationResult.adjustedScores };
    context.stageTimings['disambiguation'] = disambiguationResult.processingDurationMs;

    // Stage 7: Multi-label Selection
    const multiLabelConfig: MultiLabelSelectionConfig = {
      multiLabelPolicy: this.config.multiLabelPolicy,
      confidenceThresholds: this.config.confidenceThresholds,
      candidateScores: context.categoryScores,
    };

    const multiLabelResult = executeMultiLabelSelection(email, context, multiLabelConfig);

    context.stageTimings['multi-label-selection'] = multiLabelResult.processingDurationMs;

    // Aggregate final results (Stages 8-9 deferred to Phase 3.6)
    const pipelineEndTime = Date.now();
    const totalDuration = pipelineEndTime - pipelineStartTime;

    // Build candidate scores map
    const candidateScores: Record<string, CandidateScore> = {};
    Object.keys(context.categoryScores).forEach((category) => {
      const score = context.categoryScores[category];
      candidateScores[category] = {
        score,
        confidence: this.calculateConfidence(score),
        decision: this.determineDecision(score),
        rationale: `Score: ${score.toFixed(2)}`,
        hardAssertion: context.hardAssertionsApplied.includes(category),
      };
    });

    // Use multi-label selection results as selected labels
    const selectedLabels: SelectedLabel[] = multiLabelResult.selectedLabels;

    // Build selection summary
    const selectionSummary: SelectionSummary = {
      totalLabels: selectedLabels.length,
      primaryCategory: selectedLabels.find((l) => l.isPrimary)?.category || null,
      confidenceRange: this.calculateConfidenceRange(selectedLabels),
      selectionMethod:
        selectedLabels.length === 0 ? 'none_selected' : selectedLabels.length === 1 ? 'single_label' : 'multi_label',
      needsAi: multiLabelResult.needsAiClassification,
      topCategories: Object.entries(context.categoryScores)
        .sort(([, a], [, b]) => b - a)
        .slice(0, 3)
        .map(([category, score]) => ({ category, score })),
    };

    // Return complete classification result
    return {
      selectedLabels,
      candidateScores,
      selectionSummary,
      needsAiClassification: multiLabelResult.needsAiClassification,
      processingDurationMs: totalDuration,
    };
  } catch (error) {
    // Capture error with processing time
    const pipelineEndTime = Date.now();
    throw new Error(
      `Classification pipeline failed for email ${email.id} after ${pipelineEndTime - pipelineStartTime}ms: ${error instanceof Error ? error.message : String(error)}`
    );
  }
}

