/**
 * Classification Result Types
 *
 * Canonical types for email classification results shared across all pipeline stages.
 * These types represent the final output of the classification pipeline and intermediate
 * stage results.
 */

/**
 * Represents a selected category label with confidence, score, and selection metadata.
 *
 * This is the canonical type for selected labels across all classification stages.
 * It encompasses label selection from multi-label selection, AI routing, and final decision stages.
 *
 * @property category - The category identifier (e.g., "PERSONAL", "WORK")
 * @property subtype - Optional subtype identifier (e.g., "WORK.MEETING", "PERSONAL.FAMILY")
 * @property confidence - Confidence score (0-100) indicating certainty of classification
 * @property score - Raw classification score used for ranking
 * @property isPrimary - Whether this is the primary (highest confidence) label
 * @property labelOrder - Order of label selection (1 = primary, 2+ = secondary labels)
 * @property selectionRationale - Human-readable explanation of why this label was selected
 */
export interface SelectedLabel {
  category: string;
  subtype?: string | null;
  confidence: number;
  score: number;
  isPrimary: boolean;
  labelOrder: number;
  selectionRationale: string;
}

/**
 * Represents a candidate category with scoring details before final selection.
 *
 * @property score - Final aggregated score for the category
 * @property confidence - Confidence level derived from the score
 * @property decision - Classification decision ('positive', 'candidate', 'rejected')
 * @property rationale - Explanation of the scoring and decision
 * @property selectedSubtypeId - ID of the selected subtype if applicable
 * @property hardAssertion - Whether this score came from a hard assertion (high confidence)
 * @property scoringComponents - Breakdown of score components for explainability
 */
export interface CandidateScore {
  score: number;
  confidence: number;
  decision: 'positive' | 'candidate' | 'rejected';
  rationale?: string;
  selectedSubtypeId?: string | null;
  hardAssertion?: boolean;
  scoringComponents?: Record<string, number | string | boolean>;
}

/**
 * Summary of the multi-label selection process.
 *
 * @property totalLabels - Number of labels selected
 * @property primaryCategory - The primary (highest confidence) category
 * @property confidenceRange - Min and max confidence scores [min, max]
 * @property selectionMethod - How labels were selected ('single_label', 'multi_label', 'none_selected')
 * @property needsAi - Whether AI classification is recommended
 * @property topCategories - Top ranked categories by score
 */
export interface SelectionSummary {
  totalLabels: number;
  primaryCategory: string | null;
  confidenceRange: [number, number];
  selectionMethod: 'single_label' | 'multi_label' | 'none_selected';
  needsAi: boolean;
  topCategories?: Array<{
    category: string;
    score: number;
  }>;
}

/**
 * Complete classification result with selected labels and metadata.
 *
 * @property selectedLabels - Array of selected category labels
 * @property candidateScores - Map of all candidate scores by category
 * @property selectionSummary - Summary of the selection process
 * @property needsAiClassification - Whether AI classification is required
 * @property processingDurationMs - Time taken for classification in milliseconds
 */
export interface ClassificationResult {
  selectedLabels: SelectedLabel[];
  candidateScores: Record<string, CandidateScore>;
  selectionSummary: SelectionSummary;
  needsAiClassification: boolean;
  processingDurationMs: number;
}

/**
 * Shared Validation Utilities
 *
 * Common validation functions used across pipeline stages to ensure consistent
 * error handling and input validation. Extracted from duplicate validation logic
 * in ai-routing.ts, final-decision.ts, disambiguation.ts, and audit-trail.ts.
 *
 * Benefits:
 * - Consistent error messages across all stages
 * - Reduced code duplication
 * - Single source of truth for validation rules
 * - Easier to maintain and update validation logic
 */

import { EmailMessage, ClassificationSession } from '../types';

/**
 * Validate email input parameter
 *
 * Ensures email has either `id` or `gmail_id` field required for processing.
 * Used by stages that need to reference specific email messages.
 *
 * @param email - Email message to validate
 * @throws Error if email is null, undefined, or missing required fields
 */
export function validateEmailInput(email: EmailMessage): void {
  if (!email || (!email.id && !(email as unknown as Record<string, unknown>).gmail_id)) {
    throw new Error('Invalid email input: id or gmail_id is required');
  }
}

/**
 * Validate classification session input parameter
 *
 * Ensures session has either `id` or `session_id` field required for tracking.
 * Used by stages that need to reference specific classification sessions.
 *
 * @param session - Classification session to validate
 * @throws Error if session is null, undefined, or missing required fields
 */
export function validateSessionInput(session: ClassificationSession): void {
  if (!session || (!session.id && !(session as unknown as Record<string, unknown>).session_id)) {
    throw new Error('Invalid session input: id or session_id is required');
  }
}

/**
 * Validate configuration input parameter
 *
 * Ensures configuration is a valid object (not null, undefined, or primitive types).
 * Used by all stages that require configuration parameters.
 *
 * @param config - Configuration object to validate
 * @throws Error if config is null, undefined, or not an object
 */
export function validateConfigInput(config: unknown): void {
  if (!config || typeof config !== 'object' || Array.isArray(config)) {
    throw new Error('Configuration is required');
  }
}

/**
 * Validate confidence score value
 *
 * Ensures confidence score is a finite number (not NaN, Infinity, or -Infinity).
 * Does NOT enforce range constraints (scores can be negative or > 1 in some contexts).
 *
 * @param score - Confidence score to validate
 * @throws Error if score is NaN or infinite
 */
export function validateConfidenceScore(score: number): void {
  if (isNaN(score) || !isFinite(score)) {
    throw new Error('Invalid confidence score');
  }
}

/**
 * Validate confidence threshold value
 *
 * Ensures threshold is a finite number within [0, 1] range.
 * Used for configuration validation where thresholds must be probabilities.
 *
 * @param threshold - Confidence threshold to validate
 * @throws Error if threshold is invalid or outside [0, 1] range
 */
export function validateConfidenceThreshold(threshold: number): void {
  if (isNaN(threshold) || !isFinite(threshold) || threshold < 0 || threshold > 1) {
    throw new Error('Invalid confidence threshold');
  }
}

