/**
 * Unit Tests for Classification Pipeline Orchestrator
 *
 * TDD Approach: These tests MUST FAIL before implementation of T036i.
 * Tests validate sequential execution of all 9 stages, context propagation,
 * error handling, and complete explainability trace generation.
 */

import { ClassificationPipeline } from '../../src/pipeline/classification-pipeline';
import { EmailMessage } from '../../src/types/email-message';
import { ProcessingConfig } from '../../src/types/category-configuration';

describe('ClassificationPipeline', () => {
  // Mock email message for testing
  const mockEmail: EmailMessage = {
    id: 'test-msg-001',
    threadId: 'thread-001',
    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: 'Test Email' },
        { name: 'From', value: 'sender@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Date', value: new Date().toISOString() },
      ],
      body: {
        data: Buffer.from('Test email body content').toString('base64url'),
      },
    },
    subject: 'Test Email',
    from: { email: 'sender@example.com', name: 'Sender', raw: 'Sender <sender@example.com>' },
    to: [{ email: 'recipient@example.com', name: 'Recipient', raw: 'Recipient <recipient@example.com>' }],
    date: new Date(),
    bodyPlain: 'Test email body content',
    isProcessed: false,
    processingPriority: 1,
  };

  // Minimal processing config for testing
  const minimalConfig: ProcessingConfig = {
    version: 1,
    taxonomy_notes: 'Test configuration for pipeline orchestrator',
    settings: {
      initialization: {
        apply_hard_assertions: true,
        seed_category_scores: true,
      },
      rule_scoring: {
        use_lexical_patterns: true,
        apply_subtype_rules: true,
        bounded_aggregation: true,
      },
      attribute_processing: {
        detect_self_sent: true,
        resolve_domains: true,
        derive_context_flags: true,
      },
      attribute_influence: {
        apply_bonuses: true,
        apply_penalties: true,
        enforce_caps: true,
      },
      disambiguation: {
        pairwise_adjustments: true,
        confidence_gap_threshold: 0.15,
      },
      multi_label_selection: {
        max_labels: 2,
        min_secondary_confidence: 0.6,
        allowed_combinations: [],
      },
      ai_routing: {
        high_confidence_threshold: 0.8,
        ai_required_threshold: 0.5,
        skip_ai_conditions: [],
      },
    },
    confidence_thresholds: {
      high_confidence: 0.8,
      medium_confidence: 0.5,
      low_confidence: 0.3,
      ai_classification_required: 0.6,
      manual_review_required: 0.2,
      secondary_label_min_gap: 0.15,
    },
    category_signals: {},
    multi_label_policy: {
      max_top_level_labels: 2,
      min_confidence_for_additional: 0.6,
      min_delta_primary_secondary: 0.15,
      allow_financial_actionable_copresence: false,
